1617	// walkUpClosureCandidate checks if parent should be auto-closed as a dead-intermediate
1618	// and closes it if criteria are met: execution-eligible==false AND all children closed
1619	// AND has children. Single-hop only; does not chase the grandparent.
1620	func (s *Store) walkUpClosureCandidate(parentID string, allBeads []Bead, visited map[string]bool) {
1621		parent := findBeadByID(allBeads, parentID)
1622		if parent == nil {
1623			return
1624		}
1625	
1626		// Count children to check closure eligibility
1627		openChildCount := 0
1628		totalChildCount := 0
1629		for _, b := range allBeads {
1630			if b.Parent == parentID {
1631				totalChildCount++
1632				if b.Status != StatusClosed {
1633					openChildCount++
1634				}
1635			}
1636		}
1637	
1638		// Check closure criteria: execution-eligible==false AND no open children AND has children
1639		executionEligible, executionEligibleKnown := lifecycleExecutionEligible(*parent)
1640		if !executionEligibleKnown || executionEligible {
1641			// execution-eligible is not explicitly false, skip
1642			return
1643		}
1644		if openChildCount > 0 || totalChildCount == 0 {
1645			// Still has open children or no children at all, skip
1646			return
1647		}
1648	
1649		// All criteria met: close the parent as a dead-intermediate
1650		visited[parentID] = true
1651		_ = s.SetLifecycleStatus(parentID, StatusClosed, LifecycleTransitionOptions{
1652			ManualClose: true,
1653			Reason:      "auto-close dead-intermediate (all children closed, not execution-eligible)",
1654			Source:      "Store.Close.walkUpClosureCandidate",
1655		})
1656		_ = s.externalizeEvents(parentID)
1657		_ = s.AppendEvent(parentID, BeadEvent{
1658			Kind:      "dead_intermediate_close",
1659			Summary:   "closed as dead-intermediate bead (all children closed, execution-eligible=false)",
