2640	func sortBeadsForQueue(beads []Bead) {
2641		sort.SliceStable(beads, func(i, j int) bool {
2642			if beads[i].Priority != beads[j].Priority {
2643				return beads[i].Priority < beads[j].Priority
2644			}
2645			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
2646			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
2647			if iok != jok {
2648				return iok
2649			}
2650			if iok && jok && ir != jr {
2651				return ir < jr
2652			}
2653			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
2654				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
2655			}
2656			return beads[i].ID < beads[j].ID
2657		})
2658	}
