// ReapResult holds one epic that qualifies for reaping (all children terminal).
type ReapResult struct {
	ID             string
	Title          string
	TotalChildren  int
	ClosedChildren int
	Cancelled      int
}

// Reap returns all open/in_progress epics whose children are all terminal
// (closed or cancelled). If apply is true, it closes each one in a batch.
// Epics with no children are left alone.
func (s *Store) Reap(ctx context.Context, apply bool) ([]ReapResult, error) {
	all, err := s.ReadAll(ctx)
	if err != nil {
		return nil, err
	}

	childCount := make(map[string]int)
	closedCount := make(map[string]int)
	cancelledCount := make(map[string]int)
	for _, b := range all {
		if b.Parent != "" {
			childCount[b.Parent]++
			switch b.Status {
			case StatusClosed:
				closedCount[b.Parent]++
			case StatusCancelled:
				cancelledCount[b.Parent]++
			}
		}
	}

	var results []ReapResult
	for _, b := range all {
		if b.Status == StatusClosed || b.Status == StatusCancelled {
			continue
		}
		total := childCount[b.ID]
		if total == 0 {
			continue
		}
		terminal := closedCount[b.ID] + cancelledCount[b.ID]
		if terminal < total {
			continue
		}
		if !isOrdinaryEpicContainer(b, 0, total) {
			continue
		}
		r := ReapResult{
			ID:             b.ID,
			Title:          b.Title,
			TotalChildren:  total,
			ClosedChildren: closedCount[b.ID],
			Cancelled:      cancelledCount[b.ID],
		}
		results = append(results, r)
		if apply {
			_ = s.SetLifecycleStatus(b.ID, StatusClosed, LifecycleTransitionOptions{
				ManualClose: true,
				Reason:      "reap: all children terminal (closed or cancelled)",
				Source:      "Store.Reap",
			})
			_ = s.externalizeEvents(b.ID)
			_ = s.AppendEvent(b.ID, BeadEvent{
				Kind:    "dead_intermediate_close",
				Summary: fmt.Sprintf("reaped: all %d children terminal", total),
				Body: fmt.Sprintf("closed_because: all_children_terminal\nclosed_children: %d\ncancelled_children: %d\ntotal_children: %d",
					closedCount[b.ID], cancelledCount[b.ID], total),
				Source:    "Store.Reap",
				CreatedAt: time.Now().UTC(),
			})
			_ = s.RemoveClaimHeartbeat(b.ID)
		}
	}
	return results, nil
}

