func TestReap_AllClosedIsCandidate(t *testing.T) {
	s := newTestStore(t)

	p := &Bead{
		Title:     "Epic: all closed",
		IssueType: "epic",
		Status:    StatusOpen,
		Extra:     map[string]any{ExtraExecutionElig: false},
	}
	require.NoError(t, s.Create(testCtx(), p))

	x := &Bead{Title: "Child X", Status: StatusOpen, Parent: p.ID}
	y := &Bead{Title: "Child Y", Status: StatusOpen, Parent: p.ID}
	require.NoError(t, s.Create(testCtx(), x))
	require.NoError(t, s.Create(testCtx(), y))

	// Close both children (walkup will already auto-close p, so start fresh)
	// Use a non-execution-eligible epic that won't auto-close on first close
	// by removing execution-eligible from p temporarily to test reap directly.
	// Instead: test a case where we can control p's final state.
	// Simplest: mark p's children closed via Update (bypass cascadeAndWalkUp).
	require.NoError(t, s.Update(testCtx(), x.ID, func(b *Bead) { b.Status = StatusClosed }))
	require.NoError(t, s.Update(testCtx(), y.ID, func(b *Bead) { b.Status = StatusClosed }))

	results, err := s.Reap(testCtx(), false)
	require.NoError(t, err)
	found := false
	for _, r := range results {
		if r.ID == p.ID {
			found = true
			assert.Equal(t, 2, r.TotalChildren)
			assert.Equal(t, 2, r.ClosedChildren)
		}
	}
	assert.True(t, found, "epic with all-closed children should be a reap candidate")

	// Apply and verify p is now closed
	_, err = s.Reap(testCtx(), true)
	require.NoError(t, err)
	pGot, err := s.Get(testCtx(), p.ID)
	require.NoError(t, err)
	assert.Equal(t, StatusClosed, pGot.Status)
}

